// // This module implements a 4-bit shift register with synchronous reset and serial input. On each rising edge of the clock, the shift register shifts its contents to the left instead of the right. When the reset signal is high, the shift register is reset to all ones.
module shift_reg_4bit (CLK, RST, SI, Q);
input CLK, RST, SI;
output reg [3:0] Q;

always @(posedge CLK) begin
    if (RST) begin
        Q <= 4'b0000;
    end else begin
        Q <= {SI, Q[3:1]};
    end
end

endmodule
